import React, { useState, useEffect, useRef } from 'react';
import { Outlet, useNavigate, useLocation } from 'react-router-dom';
import {
  Box, Drawer, AppBar, Toolbar, List, Typography, Divider,
  IconButton, ListItem, ListItemButton, ListItemIcon, ListItemText,
  useMediaQuery
} from '@mui/material';
import {
  Menu as MenuIcon, Dashboard as DashboardIcon, Business as BusinessIcon,
  AttachMoney as MoneyIcon, Psychology as MindsetIcon, School as SchoolIcon,
  FitnessCenter as HealthIcon, CheckCircle as CheckIcon,
  Assessment as ReportsIcon, SmartToy as AIIcon, Logout as LogoutIcon,
  EmojiEvents as TrophyIcon
} from '@mui/icons-material';
import { useAuth } from '../context/AuthContext';
import { G } from '../theme';

const drawerWidth = 252;

const menuItems = [
  { text: 'Dashboard',  icon: <DashboardIcon />, path: '/' },
  { text: 'Business',   icon: <BusinessIcon />,  path: '/business' },
  { text: 'Best Idea',  icon: <TrophyIcon />,    path: '/best-idea' },
  { text: 'Financial',  icon: <MoneyIcon />,     path: '/financial' },
  { text: 'Mindset',    icon: <MindsetIcon />,   path: '/mindset' },
  { text: 'Learning',   icon: <SchoolIcon />,    path: '/learning' },
  { text: 'Health',     icon: <HealthIcon />,    path: '/health' },
  { text: 'Check-in',   icon: <CheckIcon />,     path: '/checkin' },
  { text: 'Reports',    icon: <ReportsIcon />,   path: '/reports' },
  { text: 'AI Advisor', icon: <AIIcon />,        path: '/ai' },
];

/* ─── Forest Particle Canvas ─────────────────────────────── */
function ForestCanvas() {
  const canvasRef = useRef(null);
  const mouse = useRef({ x: -999, y: -999 });

  useEffect(() => {
    const canvas = canvasRef.current;
    const ctx = canvas.getContext('2d');
    let W = canvas.width = window.innerWidth;
    let H = canvas.height = window.innerHeight;

    const onResize = () => {
      W = canvas.width = window.innerWidth;
      H = canvas.height = window.innerHeight;
    };
    const onMove = e => { mouse.current = { x: e.clientX, y: e.clientY }; };
    window.addEventListener('resize', onResize);
    window.addEventListener('mousemove', onMove);

    // Floating leaf particles
    const leaves = Array.from({ length: 55 }, () => ({
      x: Math.random() * W,
      y: Math.random() * H,
      size: Math.random() * 4 + 1.5,
      speedX: (Math.random() - 0.5) * 0.35,
      speedY: (Math.random() - 0.5) * 0.25,
      opacity: Math.random() * 0.35 + 0.08,
      color: [G.pine, G.fern, G.mid, G.moss, G.leaf, G.sage, G.mint][Math.floor(Math.random() * 7)],
      pulse: Math.random() * Math.PI * 2,
    }));

    // Flowing connection lines data
    const nodes = Array.from({ length: 20 }, () => ({
      x: Math.random() * W,
      y: Math.random() * H,
      vx: (Math.random() - 0.5) * 0.4,
      vy: (Math.random() - 0.5) * 0.3,
    }));

    let raf;
    let frame = 0;

    const draw = () => {
      ctx.clearRect(0, 0, W, H);
      frame++;

      // ── Background gradient
      const bg = ctx.createLinearGradient(0, 0, W, H);
      bg.addColorStop(0,   '#f2faf5');
      bg.addColorStop(0.5, '#eaf6ef');
      bg.addColorStop(1,   '#f2faf5');
      ctx.fillStyle = bg;
      ctx.fillRect(0, 0, W, H);

      // ── Subtle dot grid
      ctx.fillStyle = 'rgba(71,133,89,0.055)';
      for (let gx = 0; gx < W; gx += 38) {
        for (let gy = 0; gy < H; gy += 38) {
          ctx.beginPath();
          ctx.arc(gx, gy, 1, 0, Math.PI * 2);
          ctx.fill();
        }
      }

      // ── Mouse glow
      const mx = mouse.current.x, my = mouse.current.y;
      if (mx > 0) {
        const glow = ctx.createRadialGradient(mx, my, 0, mx, my, 260);
        glow.addColorStop(0,   'rgba(71,133,89,0.11)');
        glow.addColorStop(0.5, 'rgba(45,106,79,0.05)');
        glow.addColorStop(1,   'transparent');
        ctx.fillStyle = glow;
        ctx.beginPath();
        ctx.arc(mx, my, 260, 0, Math.PI * 2);
        ctx.fill();
      }

      // ── Organic background blobs
      const blobs = [
        { cx: W * 0.85, cy: H * 0.12, r: 300, c: 'rgba(95,188,130,0.06)' },
        { cx: W * 0.05, cy: H * 0.75, r: 280, c: 'rgba(45,106,79,0.05)' },
        { cx: W * 0.5,  cy: H * 0.5,  r: 200, c: 'rgba(148,204,171,0.04)' },
      ];
      blobs.forEach(b => {
        const shift = Math.sin(frame * 0.008) * 18;
        const grad = ctx.createRadialGradient(b.cx + shift, b.cy, 0, b.cx + shift, b.cy, b.r);
        grad.addColorStop(0, b.c);
        grad.addColorStop(1, 'transparent');
        ctx.fillStyle = grad;
        ctx.beginPath();
        ctx.arc(b.cx + shift, b.cy, b.r, 0, Math.PI * 2);
        ctx.fill();
      });

      // ── Node lines (web of green connections)
      nodes.forEach(n => {
        n.x += n.vx; n.y += n.vy;
        if (n.x < 0 || n.x > W) n.vx *= -1;
        if (n.y < 0 || n.y > H) n.vy *= -1;
        // mouse repulsion
        const dx = n.x - mx, dy = n.y - my;
        const dist = Math.sqrt(dx * dx + dy * dy);
        if (dist < 120) { n.vx += dx / dist * 0.15; n.vy += dy / dist * 0.15; }
        // speed cap
        const spd = Math.sqrt(n.vx * n.vx + n.vy * n.vy);
        if (spd > 1.2) { n.vx = n.vx / spd * 1.2; n.vy = n.vy / spd * 1.2; }
      });
      nodes.forEach((a, i) => {
        nodes.slice(i + 1).forEach(b => {
          const dx = a.x - b.x, dy = a.y - b.y;
          const d = Math.sqrt(dx * dx + dy * dy);
          if (d < 150) {
            ctx.strokeStyle = `rgba(71,133,89,${(1 - d / 150) * 0.12})`;
            ctx.lineWidth = 0.8;
            ctx.beginPath(); ctx.moveTo(a.x, a.y); ctx.lineTo(b.x, b.y); ctx.stroke();
          }
        });
      });

      // ── Floating leaf particles
      leaves.forEach(p => {
        p.pulse += 0.018;
        p.x += p.speedX + Math.sin(p.pulse) * 0.12;
        p.y += p.speedY;
        if (p.x < -10) p.x = W + 10;
        if (p.x > W + 10) p.x = -10;
        if (p.y < -10) p.y = H + 10;
        if (p.y > H + 10) p.y = -10;

        // mouse attraction (subtle)
        const dx = mx - p.x, dy = my - p.y;
        const d = Math.sqrt(dx * dx + dy * dy);
        if (d < 100 && d > 0) { p.x += dx / d * 0.3; p.y += dy / d * 0.3; }

        const pulseSize = p.size + Math.sin(p.pulse) * 0.4;
        ctx.globalAlpha = p.opacity + Math.sin(p.pulse) * 0.04;
        ctx.fillStyle = p.color;
        ctx.beginPath();
        ctx.arc(p.x, p.y, pulseSize, 0, Math.PI * 2);
        ctx.fill();
      });
      ctx.globalAlpha = 1;

      raf = requestAnimationFrame(draw);
    };
    raf = requestAnimationFrame(draw);

    return () => {
      window.removeEventListener('resize', onResize);
      window.removeEventListener('mousemove', onMove);
      cancelAnimationFrame(raf);
    };
  }, []);

  return (
    <canvas ref={canvasRef} style={{
      position: 'fixed', inset: 0, zIndex: 0, pointerEvents: 'none', display: 'block'
    }} />
  );
}

/* ─── SW PG Logo ─────────────────────────────────────────── */
function Logo({ size = 42 }) {
  return (
    <Box sx={{
      width: size, height: size,
      borderRadius: Math.round(size * 0.25),
      background: G.btnGrad,
      display: 'flex', alignItems: 'center', justifyContent: 'center',
      boxShadow: `0 4px 16px rgba(45,106,79,0.55)`,
      position: 'relative', overflow: 'hidden', flexShrink: 0,
      '&::after': {
        content: '""', position: 'absolute', inset: 0,
        background: 'linear-gradient(135deg, rgba(255,255,255,0.18) 0%, transparent 60%)',
      }
    }}>
      <Typography sx={{
        fontSize: size * 0.26, fontWeight: 900, color: '#e8f5ee',
        letterSpacing: '-0.5px', zIndex: 1, fontFamily: '"Georgia", serif',
        textShadow: '0 1px 4px rgba(0,0,0,0.25)',
      }}>SW</Typography>
    </Box>
  );
}

/* ─── Layout ─────────────────────────────────────────────── */
export default function Layout() {
  const [mobileOpen, setMobileOpen] = useState(false);
  const navigate  = useNavigate();
  const location  = useLocation();
  const { user }  = useAuth();
  const isMobile  = useMediaQuery('(max-width:600px)');

  const drawer = (
    <Box sx={{ height: '100%', display: 'flex', flexDirection: 'column', background: G.sidebarGrad }}>
      {/* Brand */}
      <Box sx={{ p: 3, display: 'flex', alignItems: 'center', gap: 1.5 }}>
        <Logo size={44} />
        <Box>
          <Typography sx={{ fontWeight: 900, fontSize: '1.15rem', color: G.foam, letterSpacing: '-0.3px', lineHeight: 1.1 }}>
            SW PG
          </Typography>
          <Typography sx={{ fontSize: '0.6rem', color: 'rgba(232,245,238,0.42)', letterSpacing: 2.5, textTransform: 'uppercase' }}>
            Personal OS
          </Typography>
        </Box>
      </Box>

      <Divider sx={{ borderColor: 'rgba(232,245,238,0.08)', mx: 2, mb: 1 }} />

      {/* Nav items */}
      <List sx={{ px: 1.5, flex: 1 }}>
        {menuItems.map(item => {
          const active = location.pathname === item.path ||
            (item.path !== '/' && location.pathname.startsWith(item.path));
          return (
            <ListItem key={item.text} disablePadding sx={{ mb: 0.5 }}>
              <ListItemButton
                onClick={() => { navigate(item.path); if (isMobile) setMobileOpen(false); }}
                sx={{
                  borderRadius: 2, px: 2, py: 1,
                  bgcolor: active ? 'rgba(148,204,171,0.18)' : 'transparent',
                  border: `1px solid ${active ? 'rgba(148,204,171,0.35)' : 'transparent'}`,
                  transition: 'all 0.18s ease',
                  '&:hover': {
                    bgcolor: 'rgba(148,204,171,0.12)',
                    border: '1px solid rgba(148,204,171,0.22)',
                    transform: 'translateX(4px)',
                  },
                }}
              >
                <ListItemIcon sx={{ minWidth: 36, color: active ? G.mint : 'rgba(232,245,238,0.38)' }}>
                  {item.icon}
                </ListItemIcon>
                <ListItemText primary={item.text} primaryTypographyProps={{
                  fontWeight: active ? 700 : 500,
                  color: active ? G.foam : 'rgba(232,245,238,0.55)',
                  fontSize: '0.875rem',
                }} />
                {active && (
                  <Box sx={{ width: 3, height: 20, borderRadius: 2, bgcolor: G.mint, ml: 0.5 }} />
                )}
              </ListItemButton>
            </ListItem>
          );
        })}
      </List>

      <Divider sx={{ borderColor: 'rgba(232,245,238,0.08)', mx: 2 }} />
      <Box sx={{ p: 1.5 }}>
        <ListItemButton sx={{
          borderRadius: 2, px: 2, py: 1,
          '&:hover': { bgcolor: 'rgba(220,60,60,0.15)' }, transition: 'all 0.18s'
        }}>
          <ListItemIcon sx={{ minWidth: 36, color: 'rgba(232,245,238,0.28)' }}>
            <LogoutIcon fontSize="small" />
          </ListItemIcon>
          <ListItemText primary="Logout" primaryTypographyProps={{ color: 'rgba(232,245,238,0.3)', fontSize: '0.85rem' }} />
        </ListItemButton>
      </Box>
    </Box>
  );

  const pageTitle = menuItems.find(m => m.path === location.pathname)?.text || 'Dashboard';

  return (
    <Box sx={{ display: 'flex', minHeight: '100vh', position: 'relative' }}>
      {/* Forest canvas background */}
      <ForestCanvas />

      {/* Top bar */}
      <AppBar position="fixed" elevation={0} sx={{
        zIndex: t => t.zIndex.drawer + 1,
        bgcolor: 'rgba(242,250,245,0.85)',
        backdropFilter: 'blur(16px)',
        WebkitBackdropFilter: 'blur(16px)',
        borderBottom: `1px solid rgba(71,133,89,0.15)`,
      }}>
        <Toolbar sx={{ gap: 2 }}>
          <IconButton edge="start" onClick={() => setMobileOpen(!mobileOpen)}
            sx={{ display: { sm: 'none' }, color: G.forest }}>
            <MenuIcon />
          </IconButton>
          <Box sx={{ display: { xs: 'flex', sm: 'none' } }}>
            <Logo size={30} />
          </Box>
          <Typography fontWeight={700} sx={{ flex: 1, color: G.forest, fontSize: '1rem', letterSpacing: '-0.2px' }}>
            {pageTitle}
          </Typography>
          {/* Online pill */}
          <Box sx={{
            px: 2, py: 0.6, borderRadius: 10,
            bgcolor: 'rgba(71,133,89,0.1)',
            border: `1px solid rgba(71,133,89,0.22)`,
            display: 'flex', alignItems: 'center', gap: 1,
          }}>
            <Box sx={{
              width: 7, height: 7, borderRadius: '50%', bgcolor: G.mid,
              boxShadow: `0 0 6px ${G.mid}`,
              animation: 'blink 2s ease-in-out infinite',
              '@keyframes blink': { '0%,100%': { opacity: 1 }, '50%': { opacity: 0.35 } }
            }} />
            <Typography variant="caption" sx={{ color: G.pine, fontWeight: 700 }}>
              {user?.username || 'Sirawdink'}
            </Typography>
          </Box>
        </Toolbar>
      </AppBar>

      {/* Sidebar */}
      <Box component="nav" sx={{ width: { sm: drawerWidth }, flexShrink: { sm: 0 }, zIndex: 1 }}>
        <Drawer
          variant={isMobile ? 'temporary' : 'permanent'}
          open={isMobile ? mobileOpen : true}
          onClose={() => setMobileOpen(false)}
          ModalProps={{ keepMounted: true }}
          sx={{
            '& .MuiDrawer-paper': {
              width: drawerWidth, boxSizing: 'border-box',
              border: 'none',
              boxShadow: '4px 0 24px rgba(26,61,43,0.22)',
            },
          }}
        >
          {drawer}
        </Drawer>
      </Box>

      {/* Main content */}
      <Box component="main" sx={{
        flexGrow: 1, position: 'relative', zIndex: 1,
        width: { sm: `calc(100% - ${drawerWidth}px)` },
        minHeight: '100vh',
      }}>
        <Toolbar />
        <Box sx={{ p: { xs: 2, sm: 3 } }}>
          <Outlet />
        </Box>
      </Box>
    </Box>
  );
}
